/**
 * @fileoverview ContextMenu state - active-menu tracking & global close.
 * @module module/ContextMenu/state
 */

import { zIndexRegistry } from '../shared/ZIndexRegistry.js';

/**
 * Global set tracking all currently-visible menu DOM elements.
 * Shared across all ContextMenu instances for nested-menu & click-away support.
 *
 * @type {Set<HTMLElement>}
 */
export const activeMenus = new Set();

/**
 * Close all currently visible context menus, removing them from the DOM.
 */
export function closeAll() {
    for (const m of activeMenus) {
        zIndexRegistry.release(m);
        m.remove();
    }
    activeMenus.clear();
}
