/**
 * @fileoverview ContextMenu helpers - pure utility functions.
 * @module module/ContextMenu/helpers
 */

import razyui from '../../index.js';
import { NUMS } from './constants.js';

/**
 * Determine if a menu item is disabled.
 *
 * @param {object} item - menu item config
 * @param {*} target - the trigger target element
 * @returns {boolean}
 */
export function isDisabled(item, target) {
    if (typeof item.disabled === 'function') return item.disabled(target);
    return !!item.disabled;
}

/**
 * Position a menu element within the viewport bounds.
 *
 * @param {HTMLElement} menu - the menu DOM element
 * @param {number} x - desired left position
 * @param {number} y - desired top position
 */
export function positionMenu(menu, x, y) {
    const vw = window.innerWidth;
    const vh = window.innerHeight;
    const rect = menu.getBoundingClientRect();
    const mw = rect.width || NUMS.DEFAULT_MENU_SIZE;
    const mh = rect.height || NUMS.DEFAULT_MENU_SIZE;

    if (x + mw > vw) x = Math.max(0, vw - mw - NUMS.VIEWPORT_PADDING);
    if (y + mh > vh) y = Math.max(0, vh - mh - NUMS.VIEWPORT_PADDING);
    razyui(menu).css({ left: x + 'px', top: y + 'px' });
}

/**
 * Position a sub-menu relative to its parent item, adjusting for viewport edges.
 *
 * @param {HTMLElement} sub - the sub-menu DOM element
 * @param {HTMLElement} parentItem - the parent menu item element
 */
export function positionSub(sub, parentItem) {
    const pr = parentItem.getBoundingClientRect();
    const vw = window.innerWidth;
    const vh = window.innerHeight;

    let left = pr.right + NUMS.SUBMENU_GAP;
    let top  = pr.top;
    const $sub = razyui(sub);
    $sub.css({ left: left + 'px', top: top + 'px' });

    // Measure after placing
    requestAnimationFrame(() => {
        const sr = sub.getBoundingClientRect();
        if (sr.right > vw) {
            $sub.css('left', (pr.left - sr.width - NUMS.SUBMENU_GAP) + 'px');
        }
        if (sr.bottom > vh) {
            $sub.css('top', Math.max(0, vh - sr.height - NUMS.VIEWPORT_PADDING) + 'px');
        }
    });
}
