/**
 * @fileoverview ContextMenu events - centralised event binding with AbortController.
 * @module module/ContextMenu/events
 */

import razyui from '../../index.js';
import { CLS } from './constants.js';
import { activeMenus, closeAll } from './state.js';

// ── Global document-level listeners (one-time side-effect) ────────────
// These persist for the lifetime of the app; no teardown needed.

razyui(document).on('keydown', (e) => {
    if (e.key === 'Escape' && activeMenus.size) {
        closeAll();
    }
});

razyui(document).on('pointerdown', (e) => {
    if (!activeMenus.size) return;
    for (const m of activeMenus) {
        if (m.contains(e.target)) return;
    }
    closeAll();
});

// ── Per-menu-item event binding ───────────────────────────────────────

/**
 * Bind per-menu-item event listeners (pointerenter, click, keydown).
 *
 * Called once per menu level (root and each dynamically-opened sub-menu).
 * The menu element must have `_rows` (`Array<HTMLElement>`) and `_focusState`
 * (`{ idx: number }`) attached by {@link module:module/ContextMenu/view.buildMenu}.
 *
 * Per-row contracts from view.js:
 *   `row._openSub()`   - open the sub-menu for this item (no-op if none)
 *   `row._closeSub()`  - close any open sub-menu for this item
 *   `row._onAction(e)` - fire the item's action + onSelect (only on actionable rows)
 *
 * @param {HTMLElement} menu - the menu element built by `buildMenu`
 */
export function bindMenuItemEvents(menu) {
    const rows = menu._rows;
    const focusState = menu._focusState;

    // ── Row-level listeners ──
    rows.forEach((row) => {
        // Hover -> close sibling subs, open own sub
        razyui(row).on('pointerenter', () => {
            rows.forEach(r => { if (r !== row && r._closeSub) r._closeSub(); });
            if (!razyui(row).hasClass(CLS.DISABLED) && row._openSub) row._openSub();
        });

        // Click -> fire action, then close all menus
        if (row._onAction) {
            razyui(row).on('click', (e) => {
                e.stopPropagation();
                closeAll();
                row._onAction(e);
            });
        }
    });

    // ── Keyboard navigation within this menu level ──
    razyui(menu).on('keydown', (e) => {
        if (e.key === 'ArrowDown' || e.key === 'ArrowUp') {
            e.preventDefault();
            const dir = e.key === 'ArrowDown' ? 1 : -1;
            let next = focusState.idx + dir;
            for (let i = 0; i < rows.length; i++) {
                if (next < 0) next = rows.length - 1;
                if (next >= rows.length) next = 0;
                if (!razyui(rows[next]).hasClass(CLS.DISABLED)) break;
                next += dir;
            }
            focusState.idx = next;
            rows[focusState.idx]?.focus();
        } else if (e.key === 'ArrowRight') {
            e.preventDefault();
            if (rows[focusState.idx]?._closeSub === undefined) return;
            rows[focusState.idx]?.dispatchEvent(new PointerEvent('pointerenter'));
        } else if (e.key === 'Enter') {
            e.preventDefault();
            rows[focusState.idx]?.click();
        }
    });
}

// ── Per-instance trigger binding ──────────────────────────────────────

/**
 * Bind trigger events on target elements.
 * Returns an object with `abort()` to clean up all listeners.
 *
 * @param {Elements} targets  - razyui Elements collection
 * @param {object}   config   - menu configuration
 * @param {Function} openMenuFn - (target, event, preventDefault) => void
 * @param {Function} [isActive] - () => boolean; guard to skip if destroyed
 * @returns {{ abort: Function }}
 */
export function bindTrigger(targets, config, openMenuFn, isActive = () => true) {
    const trigger = config.trigger;

    // ── Main trigger handler ──
    const handler = (e) => {
        if (!isActive()) return;
        openMenuFn(e.currentTarget, e, true);
    };

    targets.on(trigger, handler);

    // ── Touch long-press support (contextmenu trigger only) ──
    let touchHandler = null;
    let pressTimer = null;
    let pressStart = null;
    let pressPointerId = null;
    let pressTarget = null;
    let pressMoveHandler = null;
    let pressUpHandler = null;
    let longPressFired = false;

    function clearPress() {
        if (pressTimer) {
            clearTimeout(pressTimer);
            pressTimer = null;
        }
        razyui(document.body).removeClass(CLS.PRESS_LOCK);
        pressStart = null;
        pressPointerId = null;
        pressTarget = null;
        longPressFired = false;

        if (pressMoveHandler) {
            document.removeEventListener('pointermove', pressMoveHandler, false);
            pressMoveHandler = null;
        }
        if (pressUpHandler) {
            document.removeEventListener('pointerup', pressUpHandler, false);
            document.removeEventListener('pointercancel', pressUpHandler, false);
            pressUpHandler = null;
        }
    }

    if (trigger === 'contextmenu') {
        touchHandler = (e) => {
            if (!isActive()) return;
            if (e.pointerType !== 'touch' && e.pointerType !== 'pen') return;
            if (e.button && e.button !== 0) return;

            clearPress();

            pressPointerId = e.pointerId;
            pressStart = { x: e.clientX, y: e.clientY };
            pressTarget = e.currentTarget;
            longPressFired = false;
            razyui(document.body).addClass(CLS.PRESS_LOCK);

            const moveHandler = (me) => {
                if (me.pointerId !== pressPointerId) return;
                if (!pressStart) return;
                const dx = me.clientX - pressStart.x;
                const dy = me.clientY - pressStart.y;
                if (Math.hypot(dx, dy) > config.longPressMoveThreshold) {
                    clearPress();
                }
            };

            const upHandler = (ue) => {
                if (ue.pointerId !== pressPointerId) return;
                if (longPressFired) {
                    ue.preventDefault();
                    ue.stopPropagation();
                }
                clearPress();
            };

            pressMoveHandler = moveHandler;
            pressUpHandler = upHandler;

            document.addEventListener('pointermove', moveHandler, { passive: false });
            document.addEventListener('pointerup', upHandler, { passive: false });
            document.addEventListener('pointercancel', upHandler, { passive: false });

            pressTimer = setTimeout(() => {
                if (!pressTarget) return;
                longPressFired = true;
                const synthetic = {
                    clientX: e.clientX,
                    clientY: e.clientY,
                    pageX: e.pageX,
                    pageY: e.pageY,
                    preventDefault() {},
                    stopPropagation() {},
                };
                openMenuFn(pressTarget, synthetic, false);
            }, config.longPressMs);
        };

        targets.on('pointerdown', touchHandler);
    }

    // ── Cleanup handle ──
    return {
        abort() {
            targets.off(trigger);
            if (touchHandler) targets.off('pointerdown');
            clearPress();
        },
    };
}
