/**
 * @fileoverview ContextMenu view - DOM construction for menu and sub-menus.
 * @module module/ContextMenu/view
 */

import razyui from '../../index.js';
import { CLS, ARIA, ARROW_CHAR, NUMS, PART } from './constants.js';
import { isDisabled, positionSub } from './helpers.js';
import { activeMenus } from './state.js';
import { emitEvent } from '../shared/emitEvent.js';

/**
 * Recursively build a context-menu DOM tree.
 *
 * @param {Array} items - menu item configuration array
 * @param {Element} target - the trigger element
 * @param {object} cfg - menu configuration
 * @param {number} [depth=0] - nesting depth (0 = root)
 * @param {Function|null} [bindEventsFn=null] - callback invoked after a
 *        sub-menu is built so events.js can attach listeners (`(menu) => void`)
 * @returns {HTMLElement} the menu DOM element (with `_rows` and `_focusState`
 *          properties attached for event binding)
 */
export function buildMenu(items, target, cfg, depth = 0, bindEventsFn = null) {
    const menu = razyui.el('div', { className: 'context-menu ' + CLS.MENU, role: ARIA.MENU });
    PART.MENU.apply(menu);
    if (depth === 0 && cfg.className) menu.addClass(cfg.className);
    menu.css('position', 'fixed');

    const rows = [];

    items.forEach((item) => {
        if (item.divider) {
            const divider = razyui.el('div', { className: CLS.DIVIDER, role: ARIA.SEPARATOR });
            PART.DIVIDER.apply(divider);
            menu.append(divider);
            return;
        }

        const row = razyui.el('div', { className: CLS.ITEM, role: ARIA.MENUITEM });
        PART.ITEM.apply(row);

        const disabled = isDisabled(item, target);
        if (disabled) row.addClass(CLS.DISABLED);

        // Content - rich HTML slot
        if (item.content) {
            row.addClass(CLS.RICH);
            PART.RICH.apply(row);
            if (typeof item.content === 'string') {
                row.html(item.content);
            } else if (item.content instanceof Element) {
                row.append(item.content.cloneNode(true));
            }
        } else {
            // Icon
            if (item.icon) {
                const iconEl = razyui.el('span', { className: CLS.ICON, innerHTML: item.icon });
                PART.ICON.apply(iconEl);
                row.append(iconEl);
            }

            // Label
            const labelEl = razyui.el('span', { className: CLS.LABEL, textContent: item.label || '' });
            PART.LABEL.apply(labelEl);
            row.append(labelEl);

            // Shortcut hint
            if (item.shortcut) {
                const shortcutEl = razyui.el('span', { className: CLS.SHORTCUT, textContent: item.shortcut });
                PART.SHORTCUT.apply(shortcutEl);
                row.append(shortcutEl);
            }
        }

        // Sub-menu arrow
        if (item.items && item.items.length) {
            const arrowEl = razyui.el('span', { className: CLS.ARROW, innerHTML: ARROW_CHAR });
            PART.ARROW.apply(arrowEl);
            row.append(arrowEl);
        }

        // Sub-menu open / close helpers (consumed by events.js)
        let subMenu = null;
        const rowEl = row[0];

        rowEl._openSub = () => {
            if (subMenu) return;
            if (!item.items || !item.items.length) return;
            subMenu = buildMenu(item.items, target, cfg, depth + 1, bindEventsFn);
            razyui(document.body).append(subMenu);
            activeMenus.add(subMenu);
            positionSub(subMenu, rowEl);
            if (bindEventsFn) bindEventsFn(subMenu);
        };

        rowEl._closeSub = () => {
            if (!subMenu) return;
            activeMenus.delete(subMenu);
            subMenu.remove();
            subMenu = null;
        };

        // Action callback (consumed by events.js click handler)
        if (!disabled && typeof item.action === 'function') {
            rowEl._onAction = (e) => {
                item.action(item, target, e);
                emitEvent(target, 'select', { item });
                if (typeof cfg.onSelect === 'function') cfg.onSelect(item, target);
            };
        }

        rows.push(rowEl);
        menu.append(row);
    });

    rows.forEach(r => razyui(r).setAttr({ tabindex: '-1' }));

    /** @type {Array<HTMLElement>} Interactive menu-item elements */
    const menuEl = menu[0];
    menuEl._rows = rows;
    /** @type {{ idx: number }} Mutable focus-index tracker for keyboard nav */
    menuEl._focusState = { idx: NUMS.INITIAL_FOCUS_IDX };

    return menuEl;
}
